#include <stdio.h>
#include <stdbool.h>

bool unique(int n) {
    int mask = 0;
    while (n > 0) {
        int d = n % 10;
        if (mask & (1 << d)) return false;
        mask |= 1 << d;
        n /= 10;
    }
    return true;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int X; scanf("%d", &X);
        int Y = X + 1;
        while (!unique(Y)) ++Y;
        printf("%d\n", Y);
    }
    return 0;
}

