import sys

def unique(n: int) -> bool:
    mask = 0
    while n:
        d = n % 10
        if mask & (1 << d):
            return False
        mask |= 1 << d
        n //= 10
    return True

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        x = int(data[idx]); idx += 1
        y = x + 1
        while not unique(y):
            y += 1
        out.append(str(y))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

